-- AEGIS baseline schema (squashed).
-- Consolidates the historical 001..027 migrations into one file for fresh
-- installs. Generated by applying all 27 migrations to a clean pgvector/pg16
-- database and dumping the resulting schema (pg_dump --schema-only), then:
--   * stripped pg_dump/psql preamble (SET, \restrict, search_path) so the
--     asyncpg runner can execute it as a single statement batch;
--   * dropped the dead knowledge_source_quality.review_confidence column;
--   * added the infra registry + resources.infra_id link (new in this cut).
-- Fresh installs run only this file. Existing deployments keep their applied
-- 001..027 rows and never see it (runner tracks by filename).


-- Name: maou; Type: SCHEMA; Schema: -; Owner: -

CREATE SCHEMA maou;

-- Name: pandoras_actor; Type: SCHEMA; Schema: -; Owner: -

CREATE SCHEMA pandoras_actor;

-- Name: vector; Type: EXTENSION; Schema: -; Owner: -

CREATE EXTENSION IF NOT EXISTS vector WITH SCHEMA public;

-- Name: EXTENSION vector; Type: COMMENT; Schema: -; Owner: -

COMMENT ON EXTENSION vector IS 'vector data type and ivfflat and hnsw access methods';

-- Name: receipt_email; Type: TABLE; Schema: maou; Owner: -

CREATE TABLE maou.receipt_email (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    message_id text NOT NULL,
    account text NOT NULL,
    sender text NOT NULL,
    subject text,
    received_at timestamp with time zone NOT NULL,
    charge_id uuid,
    parsed jsonb,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);

