-- =====================================================================
-- Public: infrastructure registry (dynamic hosts + provisioning)
-- =====================================================================

CREATE TABLE public.infra (
    id                   uuid DEFAULT gen_random_uuid() NOT NULL,
    slug                 text NOT NULL,
    name                 text NOT NULL,
    kind                 text DEFAULT 'ssh_host' NOT NULL,   -- ssh_host | swarm | docker | k8s
    host                 text,
    ssh_user             text,
    ssh_port             integer DEFAULT 22 NOT NULL,
    ssh_key_ref          text,                                -- path to private key on the core host
    docker_context       text,
    hosts_aegis          boolean DEFAULT false NOT NULL,      -- the entry that runs AEGIS itself (System monitoring)
    setup_files          jsonb DEFAULT '[]'::jsonb NOT NULL,  -- [{path, content, mode}] pushed on provision
    setup_command        text,                                -- optional command run after files are written
    status               text DEFAULT 'unprovisioned' NOT NULL, -- unprovisioned | provisioning | ready | error
    last_provisioned_at  timestamp with time zone,
    last_error           text,
    metadata             jsonb DEFAULT '{}'::jsonb NOT NULL,
    created_at           timestamp with time zone DEFAULT now() NOT NULL,
    updated_at           timestamp with time zone DEFAULT now() NOT NULL
);

ALTER TABLE ONLY public.infra ADD CONSTRAINT infra_pkey PRIMARY KEY (id);
ALTER TABLE ONLY public.infra ADD CONSTRAINT infra_slug_key UNIQUE (slug);
CREATE INDEX infra_hosts_aegis_idx ON public.infra (hosts_aegis) WHERE hosts_aegis;

-- Optional link: a resource (esp. a repository) can belong to an infra entry.
ALTER TABLE public.resources ADD COLUMN infra_id uuid;
ALTER TABLE ONLY public.resources
    ADD CONSTRAINT resources_infra_id_fkey FOREIGN KEY (infra_id) REFERENCES public.infra(id) ON DELETE SET NULL;
CREATE INDEX resources_infra_id_idx ON public.resources (infra_id) WHERE infra_id IS NOT NULL;
